mapper.select:
SELECT r.report_id AS reportId, r.reporter_id AS reporterId, m2.nickname AS reporterNickname, r.target_type AS targetType, r.target_id AS targetId, r.reason, r.status, TO_CHAR(r.created_at, 'YYYY-MM-DD HH24:MI') AS createdAt FROM report r JOIN member1 m1 ON m1.member_id = r.reporter_id JOIN member2 m2 ON m2.member_id = m1.member_id
WHERE r.target_type = #{targetType} AND r.target_id = #{targetId}
WHERE 1=1
AND r.target_type = #{targetType}
ORDER BY r.created_at DESC

SELECT DBMS_LOB.SUBSTR(content, 4000, 1)
FROM   feed_post
WHERE  post_id = #{postId}

SELECT title || CHR(10) || CHR(10) || content
FROM   freeboard
WHERE  board_id = #{boardId}

SELECT title || CHR(10) || CHR(10) || content
FROM   travel_mate
WHERE  mate_id = #{mateId}
